SELECT etf_name, inception_date, asset_size
FROM etf_overviews
WHERE is_active = 1;

SELECT report_type, report_date, report_size, status
FROM etf_reports
WHERE status = 'final';

SELECT SUM(report_size) AS total_report_size
FROM etf_reports
WHERE etf_id = 1 AND status = 'final';

SELECT report_file_path
FROM etf_reports
WHERE report_id = 0;

SELECT AVG(management_fee) AS average_management_fee, COUNT(*) AS total_etfs_with_current_fee
FROM etf_fees
WHERE is_current = 1;

SELECT expense_type_id, expense_ratio
FROM etf_expenses
WHERE is_current = 1;

SELECT report_type, report_size
FROM etf_reports
ORDER BY report_size DESC;

SELECT total_expense, net_expense
FROM etf_fees
WHERE is_current = 1;

SELECT COUNT(*) AS active_category_count
FROM etf_categories
WHERE is_active = 1;
